import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import useAuthStore from '../store/authStore';
import './Auth.css';

export default function DangKy() {
  const [form, setForm] = useState({ hoTen: '', email: '', soDienThoai: '', matKhau: '', xacNhanMatKhau: '' });
  const { dangKy, loading, error } = useAuthStore();
  const navigate = useNavigate();

  const handleSubmit = async e => {
    e.preventDefault();
    if (form.matKhau !== form.xacNhanMatKhau) { toast.error('Mật khẩu xác nhận không khớp'); return; }
    const ok = await dangKy({ hoTen: form.hoTen, email: form.email, soDienThoai: form.soDienThoai, matKhau: form.matKhau });
    if (ok) { toast.success('Đăng ký thành công!'); navigate('/xac-thuc'); }
    else toast.error(error || 'Đăng ký thất bại');
  };

  const set = (k, v) => setForm(f => ({...f, [k]: v}));

  return (
    <div className="auth-wrapper">
      <div className="auth-card card">
        <div className="card-body">
          <div className="auth-logo">🏠 RoomMate</div>
          <h2 className="auth-title">Đăng ký tài khoản</h2>
          <p className="auth-subtitle">Tham gia cộng đồng hàng nghìn người!</p>
          {error && <div className="alert alert-danger">{error}</div>}
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label className="form-label">Họ và tên</label>
              <input className="form-control" required value={form.hoTen}
                onChange={e => set('hoTen', e.target.value)} placeholder="Nguyễn Văn A" />
            </div>
            <div className="grid-2">
              <div className="form-group">
                <label className="form-label">Email</label>
                <input className="form-control" type="email" required value={form.email}
                  onChange={e => set('email', e.target.value)} placeholder="example@email.com" />
              </div>
              <div className="form-group">
                <label className="form-label">Số điện thoại</label>
                <input className="form-control" required value={form.soDienThoai}
                  onChange={e => set('soDienThoai', e.target.value)} placeholder="0901234567" />
              </div>
            </div>
            <div className="grid-2">
              <div className="form-group">
                <label className="form-label">Mật khẩu</label>
                <input className="form-control" type="password" required value={form.matKhau}
                  onChange={e => set('matKhau', e.target.value)} placeholder="••••••••" />
              </div>
              <div className="form-group">
                <label className="form-label">Xác nhận mật khẩu</label>
                <input className="form-control" type="password" required value={form.xacNhanMatKhau}
                  onChange={e => set('xacNhanMatKhau', e.target.value)} placeholder="••••••••" />
              </div>
            </div>
            <button className="btn btn-primary btn-block" disabled={loading}>
              {loading ? '⏳ Đang đăng ký...' : '✨ Tạo tài khoản'}
            </button>
          </form>
          <p className="auth-footer">
            Đã có tài khoản? <Link to="/dang-nhap">Đăng nhập</Link>
          </p>
        </div>
      </div>
    </div>
  );
}
